/**
 * ListOfFigures — auto-generated from the framework's xref-registry.
 *
 * Reads `website.xref.entries`, filters by kind=figure, and renders
 * each entry as "Figure N — Caption". Entries are emitted in registry
 * insertion order, which matches document order (the registry is
 * populated by a tree walk during content collection).
 *
 * Heading defaults to "List of Figures"; override via params.title.
 */
export default {
    defaults: {
        title: 'List of Figures',
    },
}
